import React from "react";
import { format } from "date-fns";

export default function ProfileScreen({ user = { name: "", email: "", joinedDate: "" }, onLogout, darkMode }) {
  return (
    <div className={`px-6 pb-24 min-h-screen ${darkMode ? "bg-gray-900 text-gray-100" : "bg-gray-50 text-gray-900"}`}>
      <h1 className="text-2xl font-bold mb-6">Profile</h1>

      <div className={`bg-white dark:bg-gray-800 p-6 rounded-2xl shadow-sm space-y-4`}>
        <p><span className="font-semibold">Name:</span> {user.name}</p>
        <p><span className="font-semibold">Email:</span> {user.email}</p>
        <p>
          <span className="font-semibold">Joined:</span>{" "}
          {user.joinedDate ? format(new Date(user.joinedDate), "PPP") : "-"}
        </p>
      </div>

      <button
        onClick={onLogout}
        className="mt-6 w-full py-3 bg-red-600 text-white rounded-xl hover:bg-red-700 transition-colors"
      >
        Logout
      </button>
    </div>
  );
}
